cmm5mpnyl002b2ut50olmpodz	cmm5mpl7e00032ut599t7cdqn	MENTO DOS TANQUES 1. O armazenamento prolongado de diesel em um tanque pode levar ao acúmulo de borra e água em seu fundo. Esses contami- nantes podem prejudicar o funcionamento dos motores e geradores. Por esse motivo, a IM95 é equipada com um sistema de lim- peza dos tanques. Esse sistema é controlado por uma bomba manual, localizada na praça de máquinas da embarcação. 2. A operação do sistema é muito simples, bas- ta abri o registro correspondente ao tanque (LDBE, LDBB ou LDTP) a ser limpo e acio- nar o manivela da bomba manual no sentido horário. Caso exista água ou borra no fundo dos tanques ela será eliminada pela bomba, quando todos os resíduos forem eliminados, a bomba começará a eliminar diesel limpo, nesse momento deve-se parar a operação de limpeza.	20	39	[0.105442,0.08904,0.049206,0.030201,0.046603,0.03723,0.026035,0.050508,0.048946,0.038271,0.05207,0.043218,0.048685,0.046342,0.030461,0.078626,0.02994,0.036709,0.043218,0.039313,0.038532,0.049467,0.016662,0.055194,0.057017,0.056756,0.054413,0.059881,0.052591,0.058579,0.036709,0.036709,0.05181,0.053892,0.060141,0.040615,0.016662,0.05936,0.054934,0.03723,0.053372,0.054413,0.058318,0.054153,0.033585,0.054934,0.03723,0.038011,0.05233,0.053111,0.035668,0.055975,0.057537,0.055975,0.058839,0.034627,0.053892,0.03723,0.055975,0.058058,0.034627,0.060401,0.057537,0.03723,0.058839,0.051289,0.054934,0.058058,0.060662,0.052591,0.016662,0.054413,0.057798,0.034366,0.056496,0.033585,0.056756,0.055715,0.061182,0.051549,0.038011,0.018745,0.045041,0.046603,0.025514,0.043218,0.03723,0.073419,0.048165,0.048165,0.045301,0.046082,0.016662,0.054934,0.056756,0.016662,0.045301,0.046603,0.051549,0.050508,0.035928,0.016662,0.051549,0.016662,0.088519,0.053111,0.060141,0.033585,0.036449,0.053632,0.056756,0.03749,0.058839,0.034627,0.056756,0.016662,0.05181,0.056236,0.055975,0.054934,0.040615,0.020307,0.03697,0.043218,0.05962,0.038271,0.055194,0.038271,0.036709,0.051029,0.057537,0.05597